   271	        return;
   272	    }
   273	    NSError *error = nil;
   274	    NSData *data = [NSData dataWithContentsOfFile:filePath options:0 error:&error];
   275	    if (error || !data) {
   276	        return;
   277	    }
   278	    id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
   279	    if (error || ![json isKindOfClass:[NSArray class]]) {
   280	        return;
   281	    }
   282	    NSArray *entries = (NSArray *)json;
   283	    NSMutableArray<WBEvent *> *events = [NSMutableArray arrayWithCapacity:entries.count];
