   162	    if (status & (WBVappStatusWaitingDownload | WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError)) {
   163	        _progress = 0.0;
   164	    } else if (status & (WBVappStatusDownloaded | WBVappStatusInstalled | WBVappStatusResourceDownloaded | WBVappStatusResourceInstalled)) {
   165	        _progress = 1.0f;
   166	    }
   167	    
   168	    // 清理 errorInfo
   169	    if (!(status & (WBVappStatusDownloadError | WBVappStatusInstallError | WBVappStatusResourceDownloadError | WBVappStatusResourceInstallError | WBVappStatusInitError))) {
   170	        _errorInfo.errorType = WBVappStatusNone;
   171	        _errorInfo.errorDomain = @"";
   172	        _errorInfo.errorCode = 0;
   173	        _errorInfo.errorMessage = @"";
   174	    }
   175	    
   176	    [self setStatus:status];
   177	}
