    60	static NSDictionary *WBMergeBenefitUsage(NSDictionary *existing, NSArray *features) {
    61	    NSMutableSet *allowed = [NSMutableSet set];
    62	    for (id obj in features) {
    63	        if ([obj respondsToSelector:@selector(bit)]) {
    64	            NSNumber *bitNum = [obj valueForKey:@"bit"];
    65	            NSInteger bit = [bitNum integerValue];
    66	            if (bit != 0) {
    67	                [allowed addObject:[NSString stringWithFormat:@"%ld", (long)bit]];
    68	            }
    69	        }
    70	    }
    71	    NSMutableDictionary *result = [NSMutableDictionary dictionaryWithCapacity:allowed.count];
    72	    [existing enumerateKeysAndObjectsUsingBlock:^(id key, id obj, BOOL *stop) {
    73	        if ([allowed containsObject:key]) {
    74	            NSInteger integerValue = 0;
    75	            if ([obj isKindOfClass:NSNumber.class]) {
    76	                integerValue = [obj integerValue];
    77	            } else {
    78	                integerValue = [[obj description] integerValue];
    79	            }
    80	            if (integerValue < 0) integerValue = 0;
    81	            result[key] = @(integerValue);
    82	        }
    83	    }];
    84	    for (NSString *key in allowed) {
    85	        if (!result[key]) result[key] = @(0);
    86	    }
    87	    return result;
    88	}
